python3 -c "
import json, sys, os, re
d = json.load(sys.stdin)
ti = d.get('tool_input', {})
p = ti.get('file_path', '')
if not p or not p.endswith(('.ts', '.tsx')):
    sys.exit(0)
skip = ['node_modules', '.spec.', '.test.', '__tests__', '.d.ts', '.dto.', '.interface.']
if any(s in p for s in skip):
    sys.exit(0)
content = ti.get('content', '') or ti.get('new_string', '')
if not content:
    sys.exit(0)
imports = re.findall(r'from\s+[\x27\x22]([^\x27\x22]+)[\x27\x22]', content)
if not imports:
    sys.exit(0)
def has_layer(imp, keywords):
    return any(k in imp.lower() for k in keywords)
bn = os.path.basename(p).lower()
violations = []
if '.controller.' in bn:
    for imp in imports:
        if has_layer(imp, ['repository', 'entity', '.entity']):
            violations.append(f'Controller imports {imp} (should go through Service layer)')
elif '.service.' in bn:
    for imp in imports:
        if has_layer(imp, ['controller']):
            violations.append(f'Service imports {imp} (controllers depend on services, not vice versa)')
if violations:
    msg = '; '.join(violations[:2])
    print(json.dumps({'systemMessage': f'[BOUNDARY] {msg}. See coding-conventions.md Layer Boundaries.'}))
sys.exit(0)
"
